package com.google.gson.protobuf.generated;

import static org.mockito.Mockito.*;

import com.google.protobuf.ExtensionRegistry;
import com.google.protobuf.ExtensionRegistryLite;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;

import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;

class AnnotationsTest {

  ExtensionRegistry mockExtensionRegistry;
  ExtensionRegistryLite mockExtensionRegistryLite;

  @BeforeEach
  void setUp() {
    mockExtensionRegistry = mock(ExtensionRegistry.class);
    mockExtensionRegistryLite = mock(ExtensionRegistryLite.class);
  }

  @Test
  void testRegisterAllExtensions_withExtensionRegistry_invokesLiteVersion() throws Exception {
    // Use reflection to get the private static registerAllExtensions(ExtensionRegistryLite)
    Method registerAllExtensionsLite = Annotations.class.getDeclaredMethod("registerAllExtensions", ExtensionRegistryLite.class);
    registerAllExtensionsLite.setAccessible(true);

    // Spy on Annotations class to verify private method call indirectly is not possible because static private,
    // so we test the public method calls private method by reflection.
    // Call the public registerAllExtensions(ExtensionRegistry)
    Annotations.registerAllExtensions(mockExtensionRegistry);

    // We cannot verify private static method call directly with Mockito,
    // but we can invoke private method separately to ensure it runs without error
    registerAllExtensionsLite.invoke(null, mockExtensionRegistryLite);
  }

  @Test
  void testRegisterAllExtensions_withExtensionRegistryLite_runsWithoutException() {
    assertDoesNotThrow(() -> Annotations.registerAllExtensions(mockExtensionRegistryLite));
  }

  @Test
  void testGetDescriptor_returnsDescriptor() throws Exception {
    // Use reflection to access private static descriptor field
    var descriptorField = Annotations.class.getDeclaredField("descriptor");
    descriptorField.setAccessible(true);

    // Initially descriptor is null, so getDescriptor should return null or set descriptor
    Object descriptorBefore = descriptorField.get(null);
    Object descriptorReturned = Annotations.getDescriptor();
    Object descriptorAfter = descriptorField.get(null);

    // descriptorAfter may be non-null if getDescriptor initializes it, otherwise null
    assertEquals(descriptorAfter, descriptorReturned);
  }
}
